package Lec2;

public class Operators {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
// Arithmetic operators
		
// Sum of two no.'s
		
int a=6;
int b=7;
int c= a+b;
System.out.println(c);
c=b-a;
System.out.println(c);

// hence due to above code its proved that the execution of code is in sequential step by step manner 
// bcoz first due to c=a+b it print 13
// and then after due to c=b-a it print 1 



// Assignment operators

int x=8;
x+=1;  // x=x+1 : x=8+1 : x=9
System.out.println(x);

x-=1;  // x=x-1 : x=9-1 : x=8
System.out.println(x);

x*=2;  // x=x*2 : x=8*2 : x=16
System.out.println(x);

x/=2;  // x=x/2 :x=16/2 : x=8
System.out.println(x);

x%=2;  // x=x%2 : x=x%2 : x=0
System.out.println(x);










	}

}
